 1→import React from 'react';
 2→import { Layer, Group, Text } from 'react-konva';
 3→import StarGroup from '../components/StarGroup';
 4→import { getStarColor, getStarRadius } from '../utils/starUtils';
 5→
 6→const GalaxyLabel = React.memo(({ x, y, name, zoom }) => {
 7→    // Inverse-scale so the label stays a constant screen size
 8→    const invZoom = 1 / zoom;
 9→    return (
10→        <Group x={x} y={y} scaleX={invZoom} scaleY={invZoom} listening={false}>
11→            <Text
12→                text={name}
13→                fontSize={14}
14→                fill="rgba(255,255,255,0.45)"
15→                fontStyle="600"
16→                fontFamily="inherit"
17→                align="center"
18→                width={200}
19→                offsetX={100}
20→                y={-24}
21→                listening={false}
22→                perfectDrawEnabled={false}
23→            />
24→        </Group>
25→    );
26→});
27→
28→GalaxyLabel.displayName = 'GalaxyLabel';
29→
30→const InteractiveLayer = React.memo(({ layerProps, posts, galaxies, zoom, showTitles, pulsingId, onStarClick }) => {
31→    return (
32→        <Layer {...layerProps}>
33→            {/* Galaxy name labels (behind stars) */}
34→            {galaxies?.map((g) => (
35→                <GalaxyLabel
36→                    key={g.userId}
37→                    x={g.x}
38→                    y={g.y}
39→                    name={g.name}
40→                    zoom={zoom}
41→                />
42→            ))}
43→            {posts.map((post) => {
44→                const postUserId = post.users?.id;
45→                const color = getStarColor(postUserId);
46→                const likeCount = Array.isArray(post.likes) && post.likes[0]?.count != null
47→                    ? post.likes[0].count
48→                    : 0;
49→                const radius = getStarRadius(likeCount);
50→
51→                return (
52→                    <StarGroup
53→                        key={post.id}
54→                        x={post.universe_x}
55→                        y={post.universe_y}
56→                        radius={radius}
57→                        color={color}
58→                        title={post.title}
59→                        showTitle={showTitles}
60→                        isPulsing={pulsingId === post.id}
61→                        onClick={() => onStarClick(post)}
62→                    />
63→                );
64→            })}
65→        </Layer>
66→    );
67→});
68→
69→InteractiveLayer.displayName = 'InteractiveLayer';
70→
71→export default InteractiveLayer;
