  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts } from '../../../API/Api';
  6→import useUniverseCamera from './hooks/useUniverseCamera';
  7→import DeepSpaceLayer from './layers/DeepSpaceLayer';
  8→import MidGalaxyLayer from './layers/MidGalaxyLayer';
  9→import InteractiveLayer from './layers/InteractiveLayer';
 10→import { extractSnippet, userHomeCoords } from './utils/starUtils';
 11→import styles from './Universe.module.css';
 12→
 13→const Universe = () => {
 14→    const navigate = useNavigate();
 15→    const { user } = useAuth();
 16→    const userId = user?.userData?.[0]?.id || null;
 17→
 18→    const debounceRef = useRef(null);
 19→    const [posts, setPosts] = useState(new Map());
 20→    const [selectedPost, setSelectedPost] = useState(null);
 21→    const [pulsingId, setPulsingId] = useState(null);
 22→    // null = still loading, true/false = resolved
 23→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 24→
 25→    const {
 26→        stageRef,
 27→        stageSize,
 28→        camera,
 29→        zoom,
 30→        isDragging,
 31→        centerWorld,
 32→        getLayerProps,
 33→        getViewportBounds,
 34→        stageEvents,
 35→    } = useUniverseCamera(userId, hasOwnPosts);
 36→
 37→    // Debounced fetch on camera/zoom change
 38→    useEffect(() => {
 39→        if (debounceRef.current) clearTimeout(debounceRef.current);
 40→
 41→        debounceRef.current = setTimeout(async () => {
 42→            const bounds = getViewportBounds();
 43→            try {
 44→                const result = await getUniversePosts(bounds.minX, bounds.maxX, bounds.minY, bounds.maxY, 200);
 45→                if (result?.data) {
 46→                    setPosts(prev => {
 47→                        const next = new Map(prev);
 48→                        for (const post of result.data) {
 49→                            next.set(post.id, post);
 50→                        }
 51→                        return next;
 52→                    });
 53→                    // Check if any returned posts belong to this user
 54→                    if (userId && hasOwnPosts === null) {
 55→                        const ownsAny = result.data.some(p => p.users?.id === userId);
 56→                        setHasOwnPosts(ownsAny);
 57→                    }
 58→                }
 59→            } catch (err) {
 60→                console.error('Failed to fetch universe posts:', err);
 61→            }
 62→        }, 400);
 63→
 64→        return () => {
 65→            if (debounceRef.current) clearTimeout(debounceRef.current);
 66→        };
 67→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
 68→
 69→    const handleStarClick = useCallback((post) => {
 70→        setSelectedPost(post);
 71→        setPulsingId(post.id);
 72→        setTimeout(() => setPulsingId(null), 400);
 73→    }, []);
 74→
 75→    const handleReadPost = useCallback(() => {
 76→        if (!selectedPost) return;
 77→        navigate(`/home/post/${selectedPost.id}`);
 78→    }, [selectedPost, navigate]);
 79→
 80→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 81→    const showTitles = zoom > 0.5;
 82→
 83→    // Derive one label per unique user (galaxy)
 84→    const galaxies = useMemo(() => {
 85→        const seen = new Map();
 86→        for (const post of postArray) {
 87→            const uid = post.users?.id;
 88→            if (!uid || seen.has(uid)) continue;
 89→            const home = userHomeCoords(uid);
 90→            seen.set(uid, {
 91→                userId: uid,
 92→                name: post.users?.name || 'Anonymous',
 93→                x: home.x,
 94→                y: home.y,
 95→            });
 96→        }
 97→        return Array.from(seen.values());
 98→    }, [postArray]);
 99→
100→    return (
101→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
102→            <button className={styles.backButton} onClick={() => navigate('/home')}>
103→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
104→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
105→                </svg>
106→                Back
107→            </button>
108→
109→            <div className={styles.coordsLabel}>
110→                {centerWorld.x}, {centerWorld.y}
111→            </div>
112→
113→            <Stage
114→                ref={stageRef}
115→                width={stageSize.width}
116→                height={stageSize.height}
117→                {...stageEvents}
118→            >
119→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
120→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
121→                <InteractiveLayer
122→                    layerProps={getLayerProps(1.0)}
123→                    posts={postArray}
124→                    galaxies={galaxies}
125→                    zoom={zoom}
126→                    showTitles={showTitles}
127→                    pulsingId={pulsingId}
128→                    onStarClick={handleStarClick}
129→                />
130→            </Stage>
131→
132→            {selectedPost && (
133→                <div className={styles.previewPanel}>
134→                    <div className={styles.previewAuthor}>
135→                        <img
136→                            className={styles.previewAvatar}
137→                            src={selectedPost.users?.image_url || '/assets/profile.jpg'}
138→                            alt=""
139→                        />
140→                        <span className={styles.previewAuthorName}>
141→                            {selectedPost.users?.name || 'Anonymous'}
142→                        </span>
143→                    </div>
144→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
145→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
146→                    <div className={styles.previewLikes}>
147→                        {Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count
148→                            ? `${selectedPost.likes[0].count} like${selectedPost.likes[0].count !== 1 ? 's' : ''}`
149→                            : '0 likes'}
150→                    </div>
151→                    <button className={styles.previewReadBtn} onClick={handleReadPost}>
152→                        Read
153→                    </button>
154→                </div>
155→            )}
156→        </div>
157→    );
158→};
159→
160→export default Universe;
