 213→router.get('/getFollowsData', async(req, res) => {
 214→    const {userId, loggedInUserId} = req.query;
 215→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
 216→    // console.log(req.query)
 217→    try {
 218→        const followersCountPromise = supabase
 219→        .from('follows')
 220→        .select('*', {count: 'exact', head: true})
 221→        .eq('following_id', userId);
 222→
 223→        const followingCountPromise = supabase
 224→        .from('follows')
 225→        .select('*', {count: 'exact', head: true})
 226→        .eq('follower_id', userId)
 227→
 228→        const isFollowingPromise = supabase
 229→        .from('follows')
 230→        .select('*', {count: 'exact', head: true})
 231→        .eq('follower_id', loggedInUserId)
 232→        .eq('following_id', userId)
 233→
 234→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
 235→            followersCountPromise, followingCountPromise, isFollowingPromise,
 236→        ])
 237→
 238→
 239→        const {count: followersCount, error: errorFollowers } = followersCountResult;
 240→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
 241→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
 242→
 243→        if(errorFollowers || errorFollowings || errorIsfollowing){
 244→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
 245→            return res.status(500).json({error: 'failed to fetch data'})
 246→        }
 247→
 248→        return res.status(200).json({
 249→            followersCount: followersCount,
 250→            followingsCount: followingsCount,
 251→            isFollowing: isFollowingCount > 0
 252→        })
 253→
 254→    } catch (error) {
 255→        console.error('Error in Promise.all:', error);
 256→        res.status(500).json({ error: 'An unexpected error occurred' });
 257→    }
 258→
 259→})
