 261→router.get('/getCountNotifications', requireAuth, async(req, res) =>{
 262→    const userId = req.userId;
 263→    if(!userId) return res.status(400).json({error: 'no userid'});
 264→
 265→    const [journalCount, opinionCount] = await Promise.all([
 266→        supabase
 267→            .from('notifications')
 268→            .select('id', {count: 'exact', head: true})
 269→            .eq('receiver_id', userId)
 270→            .eq('read', false),
 271→        supabase
 272→            .from('notification_opinions')
 273→            .select('id', {count: 'exact', head: true})
 274→            .eq('receiver_id', userId)
 275→            .eq('read', false)
 276→    ]);
 277→
 278→    if(journalCount.error || opinionCount.error){
 279→        console.error('error fetching count in notifications table', journalCount.error || opinionCount.error);
 280→        return res.status(500).json({error: 'error fecthing count in notifications table'});
 281→    }
 282→
 283→    return res.status(200).json({count: (journalCount.count || 0) + (opinionCount.count || 0)});
 284→}) 
